import React, { useState } from 'react';
import './styles/claude-theme.css';

import FileUpload from './components/FileUpload';
import ResultsPage from './components/ResultsPage';


const App: React.FC = () => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [page, setPage] = useState<'upload' | 'results'>('upload');

    const handleFileSelected = (file: File) => {
        setSelectedFile(file);
        setPage('results');
    };

    return (
        <div className="landing-page">
            {page === 'upload' && (
                <>
                    <header className="hero">
                        <div className="hero-content">
                            <img src="/logo192.png" alt="EPIFs Assistant Logo" className="hero-logo" />
                            <h1 className="hero-title">EPIFs Assistant</h1>
                            <p className="hero-subtitle">Upload your document and get instant answers to your questionnaire.</p>
                        </div>
                    </header>
                    <main className="main-content">
                        <section className="upload-section">
                            <h2>Get Started</h2>
                            <p>Attach your document below to begin. We support PDF, DOCX, and TXT files.</p>
                            <FileUpload onFileSelected={handleFileSelected} />
                            {selectedFile && (
                                <div className="file-info">
                                    <p>Selected file: <strong>{selectedFile.name}</strong></p>
                                </div>
                            )}
                        </section>
                    </main>
                </>
            )}
            {page === 'results' && selectedFile && (
                <ResultsPage file={selectedFile} />
            )}
            <footer className="footer">
                <span>© {new Date().getFullYear()} EPIFs Assistant. All rights reserved.</span>
            </footer>
        </div>
    );
};

export default App;
